var d = $input.first().json;
var target = 42800000; // FY26 AOP
var qualifiedReq = target * 5; // Shipley 5x
var captureReq = target * 3; // Shipley 3x

var qualified = (d.qualified_value || 0) + (d.identified_value || 0);
var capture = d.active_capture_value || 0;
var weighted = d.weighted_pipeline || 0;
var allocated = d.total_allocated_revenue || 0;

var qualCoverage = Math.round((qualified / qualifiedReq) * 100);
var capCoverage = Math.round((capture / captureReq) * 100);
var weightedCoverage = Math.round((weighted / target) * 100);

var qualStatus = qualCoverage >= 100 ? '🟢' : qualCoverage >= 75 ? '🟡' : '🔴';
var capStatus = capCoverage >= 100 ? '🟢' : capCoverage >= 75 ? '🟡' : '🔴';

var msg = 'PIPELINE COVERAGE REPORT — Week of ' + new Date().toLocaleDateString('en-US', {month: 'short', day: 'numeric'}) + '\n';
msg += 'OU3 (Envision) FY26 Target: $' + (target/1000000).toFixed(1) + 'M\n\n';
msg += qualStatus + ' Qualified Pipeline: $' + (qualified/1000000).toFixed(1) + 'M / $' + (qualifiedReq/1000000).toFixed(1) + 'M req (' + qualCoverage + '%)\n';
msg += capStatus + ' Active Capture: $' + (capture/1000000).toFixed(1) + 'M / $' + (captureReq/1000000).toFixed(1) + 'M req (' + capCoverage + '%)\n';
msg += 'Weighted Pipeline: $' + (weighted/1000000).toFixed(1) + 'M (' + weightedCoverage + '% of AOP)\n';
msg += 'Allocated Revenue: $' + (allocated/1000000).toFixed(1) + 'M\n\n';
msg += 'Proposals: ' + (d.proposals_in_flight || 0) + ' ($' + ((d.proposals_value || 0)/1000000).toFixed(1) + 'M)\n';
msg += 'Must-Wins: ' + (d.must_wins || 0) + '\n';

return [{ json: { message: msg, qual_coverage: qualCoverage, cap_coverage: capCoverage } }];
